import{_ as a,o as e,c as d,ag as r}from"./chunks/framework.BZohXCq9.js";const p=JSON.parse('{"title":"名探漫剧 — 项目路演","description":"","frontmatter":{"title":"名探漫剧 — 项目路演","outline":[2,3]},"headers":[],"relativePath":"novels/detective-manga/pitch.md","filePath":"novels/detective-manga/pitch.md","lastUpdated":1775308833000}'),l={name:"novels/detective-manga/pitch.md"};function o(i,t,h,n,s,u){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="名探漫剧" tabindex="-1">名探漫剧 <a class="header-anchor" href="#名探漫剧" aria-label="Permalink to &quot;名探漫剧&quot;">​</a></h1><p><strong>经典刑侦剧 × 写实国风漫画 × 2集破案短剧</strong></p><hr><h2 id="一句话" tabindex="-1">一句话 <a class="header-anchor" href="#一句话" aria-label="Permalink to &quot;一句话&quot;">​</a></h2><blockquote><p>3分钟破一案，用国风漫画复活中国最经典的探案故事。</p></blockquote><h2 id="项目概述" tabindex="-1">项目概述 <a class="header-anchor" href="#项目概述" aria-label="Permalink to &quot;项目概述&quot;">​</a></h2><p>中国有三个探案IP是国民级的：<strong>包拯、宋慈、狄仁杰</strong>。</p><p>《少年包青天》《大宋提刑官》《神探狄仁杰》——这些剧加在一起，覆盖了从80后到00后的共同记忆。但原剧动辄40集，每案5-8集，节奏对今天的观众来说太慢了。</p><p>我们要做的事很简单：<strong>把这些经典案件浓缩成2集漫剧短剧，每集3-5分钟，用写实国风漫画重新演绎。</strong></p><p>不是缩减版，是重新讲述。用漫画的视觉语言、电影级分镜、全程配音，让经典案件以一种全新的形态复活。</p><h2 id="为什么是漫剧" tabindex="-1">为什么是漫剧 <a class="header-anchor" href="#为什么是漫剧" aria-label="Permalink to &quot;为什么是漫剧&quot;">​</a></h2><h3 id="漫剧的优势" tabindex="-1">漫剧的优势 <a class="header-anchor" href="#漫剧的优势" aria-label="Permalink to &quot;漫剧的优势&quot;">​</a></h3><p><strong>成本可控，质量上限高。</strong> 不需要实拍的场地、演员、服化道成本，但可以实现实拍做不到的视觉效果——大宋的街市、阴森的密室、推理时的思维可视化。</p><p><strong>AI大幅降低制作门槛。</strong> 写实国风的场景和角色，AI生图已经非常成熟。配合人工精修和分镜设计，小团队就能产出高质量内容。</p><p><strong>天然适合短视频平台。</strong> 3-5分钟/集，竖屏友好，强悬念结构（第1集结尾留钩子），完美匹配抖音/小红书/视频号的算法偏好。</p><p><strong>漫画风格带来差异化。</strong> 市场上的探案短剧大多是真人实拍（质感参差），或者纯动画（太卡通）。写实国风漫剧是一个空白位——既有氛围感，又有辨识度。</p><h2 id="第一季-少年包青天" tabindex="-1">第一季：少年包青天 <a class="header-anchor" href="#第一季-少年包青天" aria-label="Permalink to &quot;第一季：少年包青天&quot;">​</a></h2><h3 id="为什么从少年包青天开始" tabindex="-1">为什么从少年包青天开始 <a class="header-anchor" href="#为什么从少年包青天开始" aria-label="Permalink to &quot;为什么从少年包青天开始&quot;">​</a></h3><ul><li><strong>国民度</strong>：2000年首播，豆瓣8.5+，一代人的童年</li><li><strong>案件质量</strong>：诡计精巧，有日式推理的水准</li><li><strong>角色魅力</strong>：包拯、公孙策、展昭、庞飞燕，辨识度极强</li><li><strong>视觉适配</strong>：宋代服饰、建筑天然适合国风漫画</li><li><strong>零版权风险</strong>：包拯是历史公共人物</li></ul><h3 id="选案-5案10集" tabindex="-1">选案（5案10集） <a class="header-anchor" href="#选案-5案10集" aria-label="Permalink to &quot;选案（5案10集）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>案件</th><th>核心诡计</th><th>为什么选</th></tr></thead><tbody><tr><td>1</td><td>名扬天下</td><td>密室杀人+身份置换</td><td>包拯初登场，人物全亮相，知名度最高</td></tr><tr><td>2</td><td>血祭坛</td><td>密室+暗道+心理暗示</td><td>氛围感最强，漫画视觉冲击力大</td></tr><tr><td>3</td><td>隐逸村之谜</td><td>封闭空间+集体秘密</td><td>&quot;暴风雪山庄&quot;模式，天然悬念</td></tr><tr><td>4</td><td>殿前扬威</td><td>宫廷阴谋+巧妙推理</td><td>场景升级到皇宫，画面恢弘</td></tr><tr><td>5</td><td>五鼠闹东京</td><td>连环布局+身份迷局</td><td>动作+推理双线，季终高潮</td></tr></tbody></table><h3 id="角色设定" tabindex="-1">角色设定 <a class="header-anchor" href="#角色设定" aria-label="Permalink to &quot;角色设定&quot;">​</a></h3><table tabindex="0"><thead><tr><th>角色</th><th>身份</th><th>漫画形象</th></tr></thead><tbody><tr><td><strong>包拯</strong></td><td>少年天才，面黑心正</td><td>黑面少年、眼神锐利、书生装扮但气场不凡</td></tr><tr><td><strong>公孙策</strong></td><td>包拯好友，聪明但骄傲</td><td>白衣公子、风度翩翩</td></tr><tr><td><strong>展昭</strong></td><td>御前侍卫，武功高强</td><td>利落束装、佩剑、英气逼人</td></tr><tr><td><strong>庞飞燕</strong></td><td>太师之女，古灵精怪</td><td>俏丽活泼、灵动</td></tr></tbody></table><h2 id="制作标准" tabindex="-1">制作标准 <a class="header-anchor" href="#制作标准" aria-label="Permalink to &quot;制作标准&quot;">​</a></h2><h3 id="画风-写实国风" tabindex="-1">画风：写实国风 <a class="header-anchor" href="#画风-写实国风" aria-label="Permalink to &quot;画风：写实国风&quot;">​</a></h3><ul><li>写实风格，不Q版，不日漫</li><li>宋代考据：服饰、建筑、器物贴合历史</li><li>色调沉稳，案件高潮处冷色压暗</li><li>分镜追求电影感——大特写、景深、明暗对比</li></ul><h3 id="配音-全程真人配音" tabindex="-1">配音：全程真人配音 <a class="header-anchor" href="#配音-全程真人配音" aria-label="Permalink to &quot;配音：全程真人配音&quot;">​</a></h3><ul><li>角色各有声线辨识度</li><li>旁白用&quot;讲故事&quot;的语气，不用解说腔</li><li>环境音效：街市、雨夜、衙门、推理时刻的标志性音效</li></ul><h3 id="单集节奏" tabindex="-1">单集节奏 <a class="header-anchor" href="#单集节奏" aria-label="Permalink to &quot;单集节奏&quot;">​</a></h3><p><strong>第1集·案发（3-5分钟）</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>开场氛围 → 案件发生 → 初步调查 → 关键线索 → 悬念钩子</span></span></code></pre></div><p>结尾字幕：&quot;你猜到凶手了吗？下集揭晓。&quot;</p><p><strong>第2集·破案（3-5分钟）</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>线索回顾 → 深入推理 → 真相揭露 → 动机揭示 → 余韵 + 下案预告</span></span></code></pre></div><h3 id="互动机制" tabindex="-1">互动机制 <a class="header-anchor" href="#互动机制" aria-label="Permalink to &quot;互动机制&quot;">​</a></h3><ul><li>第1集结尾放出&quot;推理挑战&quot;——观众在评论区猜凶手</li><li>第2集开头可展示&quot;观众猜测TOP3&quot;</li><li>每案画面中暗藏线索彩蛋，认真看的人可以提前猜出答案</li></ul><h2 id="受众画像" tabindex="-1">受众画像 <a class="header-anchor" href="#受众画像" aria-label="Permalink to &quot;受众画像&quot;">​</a></h2><h3 id="核心受众" tabindex="-1">核心受众 <a class="header-anchor" href="#核心受众" aria-label="Permalink to &quot;核心受众&quot;">​</a></h3><p><strong>20-35岁，看过这些经典剧的一代人</strong></p><ul><li>有童年情怀滤镜，看到&quot;少年包青天&quot;四个字就会点进来</li><li>已经不会再去看40集原剧了，但愿意花6分钟重温一个经典案件</li><li>活跃在抖音/小红书/B站</li></ul><h3 id="泛受众" tabindex="-1">泛受众 <a class="header-anchor" href="#泛受众" aria-label="Permalink to &quot;泛受众&quot;">​</a></h3><p><strong>喜欢推理/探案内容的年轻人</strong></p><ul><li>不需要看过原剧</li><li>被&quot;3分钟破一案&quot;的形式吸引</li><li>推理爱好者、国风爱好者</li></ul><h3 id="传播逻辑" tabindex="-1">传播逻辑 <a class="header-anchor" href="#传播逻辑" aria-label="Permalink to &quot;传播逻辑&quot;">​</a></h3><p>每一案都是独立的传播单元——</p><ul><li>情怀向：&quot;还记得少年包青天里最经典的这个案子吗？&quot;</li><li>推理向：&quot;这个密室杀人你能在3分钟内猜到凶手吗？&quot;</li><li>视觉向：国风漫画截图天然适合小红书传播</li></ul><h2 id="系列规划" tabindex="-1">系列规划 <a class="header-anchor" href="#系列规划" aria-label="Permalink to &quot;系列规划&quot;">​</a></h2><table tabindex="0"><thead><tr><th>季</th><th>IP</th><th>时代</th><th>风格定位</th><th>案件数</th></tr></thead><tbody><tr><td>S1</td><td>少年包青天</td><td>北宋</td><td>推理烧脑·少年感</td><td>5案10集</td></tr><tr><td>S2</td><td>大宋提刑官</td><td>南宋</td><td>法医硬核·写实沉重</td><td>5案10集</td></tr><tr><td>S3</td><td>神探狄仁杰</td><td>大唐</td><td>政治悬疑·大格局</td><td>5案10集</td></tr><tr><td>SP</td><td>三探联动</td><td>跨时空</td><td>特别企划</td><td>待定</td></tr></tbody></table><p>三季做完 = <strong>30集高质量漫剧短剧</strong>，覆盖中国古代探案题材的三大巅峰。</p><h2 id="版权策略" tabindex="-1">版权策略 <a class="header-anchor" href="#版权策略" aria-label="Permalink to &quot;版权策略&quot;">​</a></h2><table tabindex="0"><thead><tr><th>元素</th><th>风险</th><th>策略</th></tr></thead><tbody><tr><td>包拯/宋慈/狄仁杰</td><td>无</td><td>历史公共人物，自由使用</td></tr><tr><td>案件</td><td>低</td><td>基于历史典籍和民间传说重写，不照搬原剧</td></tr><tr><td>角色造型</td><td>无</td><td>全部原创设计，不模仿任何演员形象</td></tr><tr><td>台词</td><td>低</td><td>全部重新创作</td></tr></tbody></table><p><strong>参考文献</strong>：《三侠五义》《洗冤集录》《棠阴比事》《折狱龟鉴》等公共领域典籍。</p><h2 id="执行计划" tabindex="-1">执行计划 <a class="header-anchor" href="#执行计划" aria-label="Permalink to &quot;执行计划&quot;">​</a></h2><h3 id="phase-1-概念验证-2-3周" tabindex="-1">Phase 1：概念验证（2-3周） <a class="header-anchor" href="#phase-1-概念验证-2-3周" aria-label="Permalink to &quot;Phase 1：概念验证（2-3周）&quot;">​</a></h3><ul><li>角色造型设计（AI生图+人工精修）</li><li>画风测试（产出5-10张概念图）</li><li>配音风格确定（试音）</li><li>第一案&quot;名扬天下&quot;脚本编写</li></ul><h3 id="phase-2-第一案制作-2-3周" tabindex="-1">Phase 2：第一案制作（2-3周） <a class="header-anchor" href="#phase-2-第一案制作-2-3周" aria-label="Permalink to &quot;Phase 2：第一案制作（2-3周）&quot;">​</a></h3><ul><li>完成&quot;名扬天下&quot;2集漫剧</li><li>全流程跑通：脚本→分镜→画面→配音→后期</li><li>内部测试+调整</li></ul><h3 id="phase-3-发布与滚动制作-持续" tabindex="-1">Phase 3：发布与滚动制作（持续） <a class="header-anchor" href="#phase-3-发布与滚动制作-持续" aria-label="Permalink to &quot;Phase 3：发布与滚动制作（持续）&quot;">​</a></h3><ul><li>第一案发布，收集数据</li><li>根据反馈迭代</li><li>滚动制作后续4案</li><li>第一季10集全部完成后，启动第二季</li></ul><hr><blockquote><p><em>&quot;这世上的事，十件有九件看起来明白，其实都糊涂。剩下那一件看起来糊涂的，反倒是真相。&quot;</em></p></blockquote><p><strong>项目主页</strong>：<a href="/novels/detective-manga/">名探漫剧</a></p><p><strong>制作大纲</strong>：<a href="/novels/detective-manga/behind-the-scenes/outline.html">完整大纲</a></p>',63)])])}const b=a(l,[["render",o]]);export{p as __pageData,b as default};
